SELECT COUNT(1)
FROM borrow_record


        AND user_id = #{userId}


        AND item_id = #{itemId}


        AND status = #{status}


        AND requested_time >= #{startTime}


        AND requested_time <= #{endTime}

SELECT
    id, user_id, item_id, quantity, status,
    requested_time, approved_time, returned_time,
    deposit_snapshot, condition_on_borrow, condition_on_return,
    remark, create_time, update_time
FROM borrow_record


        AND user_id = #{userId}


        AND item_id = #{itemId}


        AND status = #{status}


        AND requested_time >= #{startTime}


        AND requested_time <= #{endTime}


ORDER BY requested_time DESC
LIMIT #{pageSize} OFFSET #{offset}
